use std::collections::{HashMap, HashSet, VecDeque};

fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let c = c as usize;
    // Build adjacency list
    let mut adj: Vec<Vec<usize>> = vec![vec![]; c + 1];
    for conn in connections {
        let u = conn[0] as usize;
        let v = conn[1] as usize;
        adj[u].push(v);
        adj[v].push(u);
    }

    // Precompute connected components and their nodes
    let mut component_id = vec![0; c + 1];
    let mut components: Vec<Vec<usize>> = Vec::new();
    let mut visited = vec![false; c + 1];
    let mut current_id = 0;

    for node in 1..=c {
        if !visited[node] {
            let mut queue = VecDeque::new();
            queue.push_back(node);
            visited[node] = true;
            let mut component = Vec::new();

            while let Some(u) = queue.pop_front() {
                component.push(u);
                for &v in &adj[u] {
                    if !visited[v] {
                        visited[v] = true;
                        queue.push_back(v);
                    }
                }
            }
            component.sort();
            for &u in &component {
                component_id[u] = current_id;
            }
            components.push(component);
            current_id += 1;
        }
    }

    // For each component, maintain a set of online nodes (sorted)
    let mut online: Vec<HashSet<usize>> = vec![HashSet::new(); components.len()];
    let mut online_sorted: Vec<Vec<usize>> = vec![vec![]; components.len()];
    for (comp_id, comp_nodes) in components.iter().enumerate() {
        for &node in comp_nodes {
            online[comp_id].insert(node);
            online_sorted[comp_id].push(node);
        }
        online_sorted[comp_id].sort();
    }

    let mut status = vec![true; c + 1]; // true means online
    let mut result = Vec::new();

    for query in queries {
        let query_type = query[0];
        let x = query[1] as usize;

        if query_type == 1 {
            let comp_id = component_id[x];
            if status[x] {
                result.push(x as i64);
            } else {
                let mut found = -1;
                for &node in &online_sorted[comp_id] {
                    if status[node] {
                        found = node as i64;
                        break;
                    }
                }
                result.push(found);
            }
        } else if query_type == 2 {
            status[x] = false;
        }
    }

    result
}
