use std::collections::{HashMap, HashSet, VecDeque};

struct UnionFind {
    parent: Vec<i64>,
}

impl UnionFind {
    fn new(size: i64) -> Self {
        let mut parent = vec![0; (size + 1) as usize];
        for i in 1..=size {
            parent[i as usize] = i;
        }
        UnionFind { parent }
    }

    fn find(&mut self, x: i64) -> i64 {
        if self.parent[x as usize] != x {
            self.parent[x as usize] = self.find(self.parent[x as usize]);
        }
        self.parent[x as usize]
    }

    fn union(&mut self, x: i64, y: i64) {
        let root_x = self.find(x);
        let root_y = self.find(y);
        if root_x != root_y {
            if root_x < root_y {
                self.parent[root_y as usize] = root_x;
            } else {
                self.parent[root_x as usize] = root_y;
            }
        }
    }
}

fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let mut uf = UnionFind::new(c);
    for conn in connections {
        let u = conn[0];
        let v = conn[1];
        uf.union(u, v);
    }

    let mut online_status: Vec<bool> = vec![true; (c + 1) as usize];
    let mut component_min: HashMap<i64, std::collections::BinaryHeap<std::cmp::Reverse<i64>>> = HashMap::new();

    for i in 1..=c {
        let root = uf.find(i);
        component_min.entry(root).or_insert_with(|| std::collections::BinaryHeap::new()).push(std::cmp::Reverse(i));
    }

    let mut result = Vec::new();
    for query in queries {
        let query_type = query[0];
        let x = query[1];
        if query_type == 1 {
            let root = uf.find(x);
            if online_status[x as usize] {
                result.push(x);
            } else {
                let mut found = -1;
                if let Some(heap) = component_min.get_mut(&root) {
                    while let Some(std::cmp::Reverse(min_id)) = heap.peek() {
                        if online_status[*min_id as usize] {
                            found = *min_id;
                            break;
                        } else {
                            heap.pop();
                        }
                    }
                }
                result.push(found);
            }
        } else if query_type == 2 {
            online_status[x as usize] = false;
        }
    }
    result
