fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let c = c as usize;
    let mut graph: Vec<Vec<usize>> = vec![vec![]; c + 1];
    for conn in connections {
        let u = conn[0] as usize;
        let v = conn[1] as usize;
        graph[u].push(v);
        graph[v].push(u);
    }

    // Precompute connected components and their min nodes
    let mut component_id = vec![0; c + 1];
    let mut current_id = 1;
    let mut component_mins: HashMap<usize, HashSet<usize>> = HashMap::new();

    for node in 1..=c {
        if component_id[node] == 0 {
            let mut queue = VecDeque::new();
            queue.push_back(node);
            component_id[node] = current_id;
            let mut nodes_in_component = HashSet::new();
            nodes_in_component.insert(node);

            while let Some(u) = queue.pop_front() {
                for &v in &graph[u] {
                    if component_id[v] == 0 {
                        component_id[v] = current_id;
                        nodes_in_component.insert(v);
                        queue.push_back(v);
                    }
                }
            }

            component_mins.insert(current_id, nodes_in_component);
            current_id += 1;
        }
    }

    let mut online: Vec<bool> = vec![true; c + 1];
    let mut result = Vec::new();
    let mut component_min_online: HashMap<usize, std::collections::BTreeSet<usize>> = HashMap::new();

