fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let c = c as usize;
    let mut uf = UnionFind::new(c + 1); // 1-based indexing
    for conn in connections {
        let u = conn[0] as usize;
        let v = conn[1] as usize;
        uf.union(u, v);
    }

    // Build a map from root to the set of nodes in the component
    let mut components: HashMap<usize, HashSet<usize>> = HashMap::new();
    for node in 1..=c {
        let root = uf.find(node);
        components.entry(root).or_default().insert(node);
    }

    // Track online status: true means online
    let mut online = vec![true; c + 1];
    // For each component, maintain a BinaryHeap (min-heap) of online nodes
    let mut component_heaps: HashMap<usize, std::collections::BinaryHeap<std::cmp::Reverse<usize>>> = HashMap::new();
    for node in 1..=c {
        let root = uf.find(node);
        component_heaps.entry(root).or_default().push(std::cmp::Reverse(node));
    }

    let mut result = Vec::new();
    for query in queries {
        let typ = query[0];
        let x = query[1] as usize;
        if typ == 1 {
            // Query type 1
            if online[x] {
                result.push(x as i64);
            } else {
                let root = uf.find(x);
                let heap = component_heaps.get_mut(&root).unwrap();
                let mut found = None;
                // Need to find the smallest online node in the component
                // Since BinaryHeap is a max-heap by default, we use Reverse to simulate min-heap
                let mut temp = Vec::new();
                while let Some(std::cmp::Reverse(node)) = heap.pop() {
                    if online[node] {
                        found = Some(node);
                        temp.push(std::cmp::Reverse(node));
                        break;
                    } else {
                        temp.push(std::cmp::Reverse(node));
                    }
                }
                // Push back the nodes that were popped but not used
                for item in temp {
                    heap.push(item);
                }
                if let Some(node) = found {
                    result.push(node as i64);
                } else {
                    result.push(-1);
                }
            }
        } else if typ == 2 {
            // Query type 2: set x offline
            online[x] = false;
        }
    }
    result
}
