struct UnionFind {
    parent: Vec<i64>,
}

impl UnionFind {
    fn new(size: usize) -> Self {
        let mut parent = vec![0; size + 1];
        for i in 1..=size {
            parent[i] = i as i64;
        }
        UnionFind { parent }
    }

    fn find(&mut self, x: i64) -> i64 {
        let x = x as usize;
        if self.parent[x] != x as i64 {
            self.parent[x] = self.find(self.parent[x]);
