        let root_x = self.find(x);
        let root_y = self.find(y);
        if root_x != root_y {
            self.parent[root_y as usize] = root_x;
        }
    }
}

fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let c = c as usize;
    let mut uf = UnionFind::new(c);
    for conn in connections {
        let u = conn[0];
        let v = conn[1];
        uf.union(u, v);
    }

    // Build a map from component root to the set of nodes in the component
    let mut components: HashMap<i64, HashSet<i64>> = HashMap::new();
    for node in 1..=c as i64 {
        let root = uf.find(node);
        components.entry(root).or_default().insert(node);
    }

    // For each component, maintain a BinaryHeap (min-heap) of online nodes
    let mut online: HashSet<i64> = (1..=c as i64).collect();
    let mut component_min_online: HashMap<i64, std::collections::BinaryHeap<std::cmp::Reverse<i64>>> = HashMap::new();
    for (root, nodes) in &components {
        let mut heap = std::collections::BinaryHeap::new();
        for &node in nodes {
            heap.push(std::cmp::Reverse(node));
        }
        component_min_online.insert(*root, heap);
    }

    let mut result = Vec::new();
    for query in queries {
        let query_type = query[0];
        let x = query[1];
        if query_type == 1 {
            if online.contains(&x) {
                result.push(x);
