                let heap = component_min_online.get_mut(&root).unwrap();
                let mut found = None;
                while let Some(std::cmp::Reverse(min_node)) = heap.peek() {
                    if online.contains(min_node) {
                        found = Some(*min_node);
                        break;
                    } else {
                        heap.pop();
                    }
                }
                if let Some(min_node) = found {
                    result.push(min_node);
                } else {
